namespace BgCommon;/// <summary>/// 文件夹信息与目录操作扩展方法类./// </summary>public static partial class Extensions{    /// <summary>    /// 复制一个文件夹的所有内容到另外一个文件夹.    /// </summary>    /// <param name="sourcePath">源文件夹路径.</param>    /// <param name="destinationPath">目标文件夹路径.</param>    /// <returns>如果所有操作成功则返回 true，否则返回 false.</returns>    public static bool CopyFolder(string sourcePath, string destinationPath)    {        // 如果目标文件夹不存在，则进行创建.        if (!Directory.Exists(destinationPath))        {            Directory.CreateDirectory(destinationPath);        }        bool isAllCopied = true;        // 获取并遍历源文件夹中的所有文件进行拷贝.        string[] sourceFiles = Directory.GetFiles(sourcePath);        foreach (string filePath in sourceFiles)        {            string fileName = Path.GetFileName(filePath);            string destinationFilePath = Path.Combine(destinationPath, fileName);            // 执行文件拷贝逻辑.            File.Copy(filePath, destinationFilePath, true);        }        // 获取源文件夹中的所有子文件夹并执行递归拷贝.        string[] sourceSubDirectories = Directory.GetDirectories(sourcePath);        foreach (string subDirectoryPath in sourceSubDirectories)        {            string subDirectoryName = Path.GetFileName(subDirectoryPath);            string destinationSubPath = Path.Combine(destinationPath, subDirectoryName);            // 递归调用复制文件夹内容.            if (!CopyFolder(subDirectoryPath, destinationSubPath))            {                isAllCopied = false;            }        }        return isAllCopied;    }    /// <summary>    /// 通过深度扫描异步构建包含符合搜索模式文件的目录路径缓存集合.    /// </summary>    /// <param name="baseDirectory">要扫描的根目录信息.</param>    /// <param name="searchPatterns">文件搜索模式数组，例如 ["*.jpg"].</param>    /// <param name="cancellationToken">用于取消操作的令牌.</param>    /// <param name="allowMaxDepth">驱动器根目录下允许扫描的最大深度.</param>    /// <returns>一个包含所有有效目录完整路径的哈希集合.</returns>    public static async Task<HashSet<string>> BuildValidDirectoryCacheAsync(this DirectoryInfo? baseDirectory, string[] searchPatterns, CancellationToken cancellationToken, int allowMaxDepth = 5)    {        return await Task.Run(            () => BuildValidDirectoryCache(baseDirectory, searchPatterns, allowMaxDepth, cancellationToken),            cancellationToken);    }    private static HashSet<string> BuildValidDirectoryCache(DirectoryInfo? baseDirectory, string[] searchPatterns, int allowMaxDepth, CancellationToken cancellationToken)    {        var stopwatch = new Stopwatch();        stopwatch.Start();        // 检查取消请求或对象空引用.        if (cancellationToken.IsCancellationRequested || baseDirectory == null)        {            return new HashSet<string>();        }        // 使用并发字典存储路径以确保线程安全.        ConcurrentDictionary<string, byte> validDirectoryPaths = new ConcurrentDictionary<string, byte>(StringComparer.OrdinalIgnoreCase);        string rootPath = baseDirectory.FullName;        // 确定扫描深度：如果是驱动器根目录（如 C:\），则限制深度以防止性能灾难.        int currentMaxDepth = -1;        if (baseDirectory.Parent == null)        {            currentMaxDepth = allowMaxDepth;            Trace.TraceInformation($"检测到扫描根目录为驱动器根目录，已自动限制扫描深度为 {currentMaxDepth} 层.");        }        // 安全地枚举文件信息集合.        IEnumerable<FileInfo>? matchedFiles = baseDirectory.SafeEnumerateFiles(searchPatterns, cancellationToken, currentMaxDepth);        if (matchedFiles == null)        {            stopwatch.Stop();            Trace.TraceWarning($"执行 BuildValidDirectoryCacheAsync 提前退出，耗时 {stopwatch.ElapsedMilliseconds} ms.");            return new HashSet<string>();        }        try        {            // 并行遍历所有匹配的文件，追溯其父目录.            Parallel.ForEach(matchedFiles, new ParallelOptions { CancellationToken = cancellationToken }, (fileInfo, loopState) =>            {                DirectoryInfo? currentDirectory = fileInfo.Directory;                while (currentDirectory != null)                {                    // 确保路径范围在根目录之内.                    if (!currentDirectory.FullName.StartsWith(rootPath, StringComparison.OrdinalIgnoreCase))                    {                        break;                    }                    // 将目录路径加入线程安全字典，若已存在则停止向上追溯.                    if (!validDirectoryPaths.TryAdd(currentDirectory.FullName, 0))                    {                        break;                    }                    // 到达根目录后停止向上追溯.                    if (string.Equals(currentDirectory.FullName, rootPath, StringComparison.OrdinalIgnoreCase))                    {                        break;                    }                    currentDirectory = currentDirectory.Parent;                }            });        }        catch (OperationCanceledException)        {            // 捕获取消异常，记录日志并正常结束.            Trace.TraceInformation("BuildValidDirectoryCacheAsync 操作被用户取消.");        }        stopwatch.Stop();        Trace.TraceWarning($"执行 BuildValidDirectoryCacheAsync 方法完成，耗时 {stopwatch.ElapsedMilliseconds} ms.");        return new HashSet<string>(validDirectoryPaths.Keys, StringComparer.OrdinalIgnoreCase);    }    /// <summary>    /// 安全地枚举一个目录及其子目录中的匹配文件，避免递归导致的堆栈溢出.    /// </summary>    /// <param name="directory">要搜索的起始目录.</param>    /// <param name="searchPatterns">文件搜索模式数组.</param>    /// <param name="cancellationToken">取消令牌.</param>    /// <param name="maxDepth">遍历的最大深度，-1 表示无限深度.</param>    /// <returns>一个可枚举的文件信息集合.</returns>    public static IEnumerable<FileInfo> SafeEnumerateFiles(this DirectoryInfo directory, string[] searchPatterns, CancellationToken cancellationToken, int maxDepth = -1)    {        ArgumentNullException.ThrowIfNull(directory, nameof(directory));        ArgumentNullException.ThrowIfNull(searchPatterns, nameof(searchPatterns));        // 使用栈进行迭代遍历，存储目录对象和当前深度.        Stack<(DirectoryInfo Dir, int Depth)> directoryStack = new Stack<(DirectoryInfo Dir, int Depth)>();        directoryStack.Push((directory, 0));        while (directoryStack.Count > 0)        {            // 实时检查是否取消了操作.            if (cancellationToken.IsCancellationRequested)            {                yield break;            }            var (currentDirectory, currentDepth) = directoryStack.Pop();            // 根据所有搜索模式枚举当前目录下的文件.            foreach (string pattern in searchPatterns)            {                IEnumerable<FileInfo> fileList;                try                {                    // 获取当前级目录中的匹配文件.                    fileList = currentDirectory.EnumerateFiles(pattern, SearchOption.TopDirectoryOnly);                }                catch (UnauthorizedAccessException)                {                    // 跳过无访问权限的模式或目录.                    continue;                }                catch (IOException)                {                    // 处理路径过长等 IO 异常.                    continue;                }                foreach (FileInfo fileInfo in fileList)                {                    yield return fileInfo;                }            }            // 如果设置了深度限制且已达到最大深度，则不再压入子目录.            if (maxDepth != -1 && currentDepth >= maxDepth)            {                continue;            }            // 发现并压入子目录.            try            {                foreach (DirectoryInfo subDirectory in currentDirectory.EnumerateDirectories())                {                    // 过滤隐藏目录和系统目录.                    if ((subDirectory.Attributes & FileAttributes.Hidden) == 0 && (subDirectory.Attributes & FileAttributes.System) == 0)                    {                        directoryStack.Push((subDirectory, currentDepth + 1));                    }                }            }            catch (UnauthorizedAccessException)            {                // 跳过无权限访问子目录列表的目录.                continue;            }            catch (IOException)            {                // 跳过发生 IO 错误的目录.                continue;            }        }    }}// /// <